class MyCircularDeque:
    def __init__(self, k: int):
        self.q=[0]*k; self.k=k; self.h=0; self.n=0
    def insertFront(self,v):
        if self.isFull(): return False
        self.h=(self.h-1)%self.k; self.q[self.h]=v; self.n+=1; return True
    def insertLast(self,v):
        if self.isFull(): return False
        self.q[(self.h+self.n)%self.k]=v; self.n+=1; return True
    def deleteFront(self):
        if self.isEmpty(): return False
        self.h=(self.h+1)%self.k; self.n-=1; return True
    def deleteLast(self):
        if self.isEmpty(): return False
        self.n-=1; return True
    def getFront(self): return -1 if self.isEmpty() else self.q[self.h]
    def getRear(self): return -1 if self.isEmpty() else self.q[(self.h+self.n-1)%self.k]
    def isEmpty(self): return self.n==0
    def isFull(self): return self.n==self.k

