    vector<int> q; int h,n,k;
public:
    MyCircularDeque(int k):q(k),h(0),n(0),k(k){}
    bool insertFront(int v){ if(isFull())return false; h=(h-1+k)%k; q[h]=v; n++; return true;}
    bool insertLast(int v){ if(isFull())return false; q[(h+n)%k]=v; n++; return true;}
    bool deleteFront(){ if(isEmpty())return false; h=(h+1)%k; n--; return true;}
    bool deleteLast(){ if(isEmpty())return false; n--; return true;}
    int getFront(){ return isEmpty()?-1:q[h];}
    int getRear(){ return isEmpty()?-1:q[(h+n-1+k)%k];}
    bool isEmpty(){ return n==0;}
    bool isFull(){ return n==k;}
};

